external_knowledge:
- 'decade of feedback' refers to having provided more than 10 reviews;
- 'exceptionally high satisfaction rating' means an average rating greater than 4.5;
- 'significant sum' refers to spending more than $500.

sql:
SELECT c.customer_id, c.name
FROM customers c
WHERE c.customer_id IN (
    SELECT o.customer_id
    FROM orders o
)
AND c.customer_id NOT IN (
    SELECT cf.customer_id
    FROM customer_feedback cf
);

SELECT comments
FROM customer_feedback
WHERE rating = (SELECT MAX(rating) FROM customer_feedback);
